from vex import Verifier, Check
from agno.agent import Agent

class QueryAlignmentCheck(Check):
    name = "query_planning_accuracy"

    def evaluate(self, input_data: dict, output_data: dict) -> dict:
        user_query = input_data["query"]
        planned_queries = output_data["planned_subqueries"]

        alignment_score = self.semantic_similarity(user_query, planned_queries)

        return {
            "passed": alignment_score > 0.85,
            "score": alignment_score,
            "details": f"User intent alignment: {alignment_score:.2f}"
        }

verifier = Verifier(
    checks=[
        QueryAlignmentCheck(),
        "cross_source_consistency",
        "source_faithfulness"
    ]
)

@verifier.wrap
async def run_agent(agent: Agent, query: str):
    return agent.run(query)

verified_result = run_agent(rag_agent, "Research task")

from vex.integrations.agno import VexAgnoMiddleware
from agno.agent import Agent

from functools import wraps

def vex_protected_agent(agent: Agent):
    @wraps(agent.run)
    def verified_run(self, query: str, *args, **kwargs):
        from vex import verify

        @verify(
            checks=[
                "source_faithfulness@99%",
                "no_hallucinations",
                "citation_verification",
                "cross_source_consistency"
            ],
            fallback="retry_with_simpler_query",
            max_retries=3
        )
        def _run():
            return agent.run(query, *args, **kwargs)

        return _run()

    agent.run = verified_run.__get__(agent)
    return agent

# Apply to production agent
secure_rag_agent = vex_protected_agent(rag_agent)
